const WithValidation = () => {
  const onFinish = (values: unknown) => {
    console.log('Success:', values);
  };

  return (
    <Form
      name='validation'
      layout='vertical'
      onFinish={onFinish}
      style={{width: '400px'}}
    >
      <Form.Item
        label='Username'
        name='username'
        rules={[
          {required: true, message: 'Username is required'},
          {min: 3, message: 'Username must be at least 3 characters'},
          {max: 20, message: 'Username cannot exceed 20 characters'},
        ]}
      >
        <Input placeholder='Enter username (3-20 characters)' />
      </Form.Item>

      <Form.Item
        label='Email'
        name='email'
        rules={[
          {required: true, message: 'Email is required'},
          {type: 'email', message: 'Please enter a valid email'},
        ]}
      >
        <Input placeholder='Enter email' />
      </Form.Item>

      <Form.Item
        label='Password'
        name='password'
        rules={[
          {required: true, message: 'Password is required'},
          {min: 6, message: 'Password must be at least 6 characters'},
        ]}
      >
        <Input.Password placeholder='Enter password (min 6 characters)' />
      </Form.Item>

      <Form.Item
        label='Confirm Password'
        name='confirm'
        dependencies={['password']}
        rules={[
          {required: true, message: 'Please confirm your password'},
          ({getFieldValue}) => ({
            validator(_, value) {
              if (!value || getFieldValue('password') === value) {
                return Promise.resolve();
              }
              return Promise.reject(new Error('Passwords do not match'));
            },
          }),
        ]}
      >
        <Input.Password placeholder='Confirm password' />
      </Form.Item>

      <Form.Item>
        <Button type='primary' htmlType='submit'>
          Register
        </Button>
      </Form.Item>
    </Form>
  );
};

const CustomValidation = () => {
  const onFinish = (values: unknown) => {
    console.log('Success:', values);
  };

  return (
    <Form
      name='custom'
      layout='vertical'
      onFinish={onFinish}
      style={{width: '400px'}}
    >
      <Form.Item
        label='Age'
        name='age'
        rules={[
          {required: true, message: 'Age is required'},
          {
            validator: (_, value) => {
              if (
                value &&
                (typeof value === 'number' || typeof value === 'string') &&
                (Number(value) < 18 || Number(value) > 100)
              ) {
                return Promise.reject(
                  new Error('Age must be between 18 and 100')
                );
              }
              return Promise.resolve();
            },
          },
        ]}
      >
        <Input type='number' placeholder='Enter age (18-100)' />
      </Form.Item>

      <Form.Item
        label='Website'
        name='website'
        rules={[
          {
            validator: (_, value) => {
              if (
                value &&
                typeof value === 'string' &&
                !value.match(/^https?:\/\/.+/)
              ) {
                return Promise.reject(
                  new Error(
                    'Please enter a valid URL starting with http:// or https://'
                  )
                );
              }
              return Promise.resolve();
            },
          },
        ]}
      >
